class Solution:
    def findMinDifference(self, timePoints):
        mins = [int(t[:2]) * 60 + int(t[3:]) for t in timePoints]
        best = 1440
        n = len(mins)
        for i in range(n):
            for j in range(i + 1, n):
                d = abs(mins[i] - mins[j])
                d = min(d, 1440 - d)
                best = min(best, d)
        return best

