class Solution:
    def findMinDifference(self, timePoints):
        if len(timePoints) > 1440:
            return 0
        mins = sorted(int(t[:2]) * 60 + int(t[3:]) for t in timePoints)
        best = 1440 - mins[-1] + mins[0]
        for i in range(1, len(mins)):
            best = min(best, mins[i] - mins[i - 1])
        return best

