var findMinDifference = function(timePoints) {
    if (timePoints.length > 1440) return 0;
    const mins = timePoints.map(t => parseInt(t.slice(0, 2), 10) * 60 + parseInt(t.slice(3), 10));
    mins.sort((a, b) => a - b);
    let best = 1440 - mins[mins.length - 1] + mins[0];
    for (let i = 1; i < mins.length; i++) {
        best = Math.min(best, mins[i] - mins[i - 1]);
    }
    return best;
};
